// --- REAL TOOTH IMAGES (base64) ---
const TOOTH_IMAGES = {
  '11': 'data:image/png;base64,',
  '12': 'data:image/png;base64,',
  '13': 'data:image/png;base64,',
  '14': 'data:image/png;base64,',
  '15': 'data:image/png;base64,',
  '16': 'data:image/png;base64,',
  '17': 'data:image/png;base64,',
  '18': 'data:image/png;base64,',
  '21': 'data:image/png;base64,',
  '22': 'data:image/png;base64,',
  '23': 'data:image/png;base64,',
  '24': 'data:image/png;base64,',
  '25': 'data:image/png;base64,',
};

const ToothShape = ({ type, isLower, isRightSide, toothId, isGeneratingPdf, pdfW, pdfH }) => {
  const id = String(toothId);
  const pos = toothId % 10;
  const quadrant = Math.floor(toothId / 10);
  
  let imageSrc = null;

  if (quadrant === 1) {
    // Upper right (11-18): direct images
    imageSrc = TOOTH_IMAGES[id];
  } else if (quadrant === 2) {
    // Upper left (21-25): direct images; 26-28 fall back to right-side equivalents
    imageSrc = TOOTH_IMAGES[id] || TOOTH_IMAGES[`1${pos}`];
  } else if (quadrant === 4) {
    // Lower right: use upper right image
    imageSrc = TOOTH_IMAGES[`1${pos}`];
  } else if (quadrant === 3) {
    // Lower left: use upper left image if available
    imageSrc = TOOTH_IMAGES[`2${pos}`] || TOOTH_IMAGES[`1${pos}`];
  }

  if (!imageSrc) return null;

  // CSS transforms to orient teeth correctly:
  // Q1 (upper right): images face right, mirror so they face center (left)
  // Q2 (upper left): images naturally face left/center, no flip
  // Q4 (lower right): flip both axes (root down, facing center)
  // Q3 (lower left): flip vertically only (root down, facing right toward center)
  let transform = 'none';
  if (quadrant === 1) transform = 'scaleX(-1)';
  else if (quadrant === 4) transform = 'scale(-1, -1)';
  else if (quadrant === 3) transform = 'scaleY(-1)';

  return (
    <img
      src={imageSrc}
      alt="Tooth"
      className={`object-contain ${isGeneratingPdf ? '' : 'drop-shadow-md transition-transform duration-300'}`}
      style={isGeneratingPdf ? {
        transform,
        transformOrigin: 'center center',
        width: pdfW || 24,
        height: pdfH || 46,
        display: 'block',
        flexShrink: 0,
      } : {
        transform,
        transformOrigin: 'center center',
        width: '100%',
        height: '100%',
        maxWidth: '100%',
        maxHeight: '100%',
        display: 'block',
      }}
    />
  );
};

