const UPPER_RIGHT = [18, 17, 16, 15, 14, 13, 12, 11];
const UPPER_LEFT = [21, 22, 23, 24, 25, 26, 27, 28];
const LOWER_RIGHT = [48, 47, 46, 45, 44, 43, 42, 41];
const LOWER_LEFT = [31, 32, 33, 34, 35, 36, 37, 38];

const getJawType = (toothId) => {
  const id = parseInt(toothId);
  if (id >= 11 && id <= 28) return 'Upper Jaw';
  if (id >= 31 && id <= 48) return 'Lower Jaw';
  return 'Unknown';
};

const getTreatmentStyle = (id) => {
  if (id.startsWith('impl_')) return "w-3 h-3 rounded-full bg-blue-500 shadow-sm";
  if (id.startsWith('crown_')) return "w-3 h-3 rounded-full border-[3px] border-indigo-700 bg-white shadow-sm";
  if (id.startsWith('veneer_')) return "w-3 h-3 rounded-full bg-teal-400 shadow-sm";
  if (id.startsWith('filling_')) return "w-3 h-3 rounded-full bg-amber-400 shadow-sm";
  return "w-3 h-3 rounded-full bg-gray-500 shadow-sm";
};

const getTreatmentEmoji = (id) => {
  if (id.startsWith('impl_')) return '🔩';
  if (id.startsWith('crown_')) return '👑';
  if (id.startsWith('veneer_')) return '✨';
  if (id.startsWith('filling_')) return '🟡';
  if (id === 'temp_denture') return '🦷';
  return '⚕️';
};

const TreatmentIcon = ({ treatmentId, isPdf }) => {
  const fontSize = isPdf ? '8px' : '11px';
  return (
    <span style={{ fontSize, lineHeight: 1, display: 'block' }} title={treatmentId}>
      {getTreatmentEmoji(treatmentId)}
    </span>
  );
};

const getSmallTreatmentStyle = (id, isPdf) => {
  const base = isPdf ? "w-[6px] h-[6px]" : "w-2.5 h-2.5 sm:w-3 sm:h-3";
  if (id.startsWith('impl_')) return `${base} rounded-full bg-blue-500 shadow-sm`;
  if (id.startsWith('crown_')) return `${base} rounded-full border-[1.5px] border-indigo-700 bg-white shadow-sm`;
  if (id.startsWith('veneer_')) return `${base} rounded-full bg-teal-400 shadow-sm`;
  if (id.startsWith('filling_')) return `${base} rounded-full bg-amber-400 shadow-sm`;
  return `${base} rounded-full bg-gray-500 shadow-sm`;
};

